- app/page.tsx:

```tsx
'use client';

import { cn } from "@/lib/utils";
import HeroBanner from "./hero-banner";
import MovieSection from "./movie-section";
import MovieModal from "./movie-modal";

interface Movie {
  id: string;
  title: string;
  description: string;
  rating: number; // 0-5
  genre: string;
  poster: string; // emoji or placeholder
}

// Mock data
