    poster: "🌌",
  },
  {
    id: "3",
    title: "Mystery of the Ancient Temple",
    description: "Explorers uncover secrets of an ancient temple.",
    rating: 4.8,
    genre: "Adventure",
    poster: "🏛️",
  },
  {
    id: "4",
    title: "Silent Echoes",
    description: "A haunting tale of lost memories.",
    rating: 3.9,
    genre: "Drama",
    poster: "👻",
  },
  {
    id: "5",
    title: "Future Tech",
    description: "A glimpse into the world of tomorrow's technology.",
    rating: 4.2,
    genre: "Sci-Fi",
    poster: "🤖",
  },
  {
    id: "6",
    title: "Wild Hearts",
    description: "A wild ride across the savannah.",
    rating: 4.6,
    genre: "Wildlife",
    poster: "🦁",
  },
];

export default function HomePage() {
  const [selectedMovie, setSelectedMovie] = React.useState<Movie | null>(null);
  const [isModalOpen, setIsModalOpen] = React.useState(false);

  const openModal = (movie: Movie) => {
    setSelectedMovie(movie);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedMovie(null);
  };

  // Group movies by genre or just create sections manually
  const sections = [
    {
      title: "Trending Now",
      movies: [
        movies[0],
        movies[1],
        movies[2],
        movies[3],
      ],
    },
    {
      title: "Latest Releases",
      movies: [
        movies[4],
        movies[5],
        movies[0],
        movies[2],
      ],
