MovieModal.tsx:

```tsx
'use client';

import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Card } from "@/components/ui/card";
import { Avatar } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { SunIcon, StarIcon } from "lucide-react";

interface Movie {
  id: string;
  title: string;
  description: string;
  rating: number;
  genre: string;
  poster: string;
}

interface MovieModalProps {
  movie: Movie;
  onClose: () => void;
}

export default function MovieModal({ movie, onClose }: MovieModalProps) {
  const stars = Array.from({ length: Math.round(movie.rating) }, (_, i) => i + 1);
  const emptyStars = Array.from({ length: 5 - stars.length }, (_, i) => i + 1);

  return (
    <div className="flex flex-col gap-4">
      <DialogHeader>
        <DialogTitle>{movie.title}</DialogTitle>
      </DialogHeader>
      <div className="flex items-center gap-2">
        <Avatar className="h-12 w-12">
          <AvatarFallback>{movie.poster}</AvatarFallback>
        </Avatar>
        <div>
          <p className="text-sm font-medium">{movie.genre}</p>
          <div className="flex items-center gap-0.5 mt-0.5">
            {stars.map((star) => (
              <StarIcon key={star} className="h-4 w-4 text-yellow-400" />
            ))}
            {emptyStars.map((star) => (
              <StarIcon key={star} className="h-4 w-4 text-gray-400" />
            ))}
          </div>
        </div>
      </div>
      <DialogDescription className="text-left">
        {movie.description}
      </DialogDescription>
      <div className="flex justify-end">
        <Button variant="outline" onClick={onClose}>
          Close
        </Button>
      </div>
    </div>
  );
}
```

But we need to import AvatarFallback? In Shadcn Avatar component, AvatarFallback is exported from same file. So we need to import AvatarFallback.

