'use client';

import { cn } from "@/lib/utils";
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { StarIcon } from "lucide-react";

interface Movie {
  id: string;
  title: string;
  description: string;
  rating: number;
  genre: string;
  poster: string;
}

interface MovieSectionProps {
  title: string;
  movies: Movie[];
  onSelect: (movie: Movie) => void;
}

export default function MovieSection({ title, movies, onSelect }: MovieSectionProps) {
  return (
    <section className="my-12">
      <h2 className="text-2xl font-bold mb-6">{title}</h2>
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
        {movies.map((movie) => (
          <Card
            key={movie.id}
            className="bg-gray-800 hover:bg-gray-700 transition-colors"
          >
            <CardHeader className="flex flex-col items-start gap-2">
              <Avatar className="h-10 w-10">
                <AvatarFallback>{movie.poster}</AvatarFallback>
              </Avatar>
              <CardTitle className="text-lg">{movie.title}</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-gray-300 line-clamp-2">
                {movie.description}
              </p>
            </CardContent>
            <CardFooter className="flex items-center justify-between">
              <Badge variant="outline" className="bg-transparent border border-gray-600 text-gray-300">
                {movie.genre}
              </Badge>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => onSelect(movie)}
                className="flex items-center gap-1"
              >
                Details
                <StarIcon className="h-4 w-4" />
              </Button>
            </CardFooter>
          </Card>
        ))}
      </div>
    </section>
  );
}
```

